GameSkill = {}

function GameSkill:onButtonClick(player, itemId)

    for _, Value in pairs(player.shopSkill) do
        if Value.id == itemId then
            if Value.status == Define.ItemBuyStatus.Unlock then
                self:onSkillBuy(player, itemId, true)
            elseif Value.status == Define.ItemBuyStatus.Buy then
                self:onSkillUsed(player, itemId)
            elseif Value.status == Define.ItemBuyStatus.Used then
                self:onSKillUnload(player, itemId)
            end
        end
    end
end

function GameSkill:onSkillBuy(player, itemId, needMoney)

    local skill = SkillConfig:getSkillById(itemId)
    if skill == nil then
        return
    end
    if not needMoney then
        self:onBuySuccess(player, itemId)
        return
    end
    if skill.MoneyType == Define.MoneyType.SLGolds then

        if player.property.gold >= BigNum.new(string.format("%f", skill.Price)) then
            player.property:changeGold(-skill.Price)
            self:onBuySuccess(player, itemId)
        else
            HostApi.sendCommonTip(player.rakssid, "gold_enough")
        end

    end

    if skill.MoneyType == Define.MoneyType.DiamondGolds1 then
        PayHelper.payDiamondsSync(player.userId, skill.Id, skill.Price, function(player)
            self:onBuySuccess(player, itemId)
        end, nil)
    end

    if skill.MoneyType == Define.MoneyType.DiamondGolds2 then
        PayHelper.payDiamondsSync(player.userId, skill.Id, skill.Price, function(player)
            self:onBuySuccess(player, itemId)
        end, nil)
    end

    ReportUtil.reportSkillBuy(player, itemId)
end
