function GameSkill:onSKillUnload(player, itemId)


    for _, Value in pairs(player.equipmentSkill) do
        if Value.id == itemId  then
            Value.id = 0
            GamePacketSender:SendEquipSkill(player.rakssid, Value.id, Value.position, true)
            break
        end
    end


    local data = {}
    for _, Value in pairs(player.shopSkill) do
        if Value.id == itemId then
            Value.status = Define.ItemBuyStatus.Buy
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end
    end
    ShopManager:senderSkillInfo(player, data)
    GameSkill:shareDataToTokenSkill(player, data)
end

function GameSkill:initSkillItem(player)

    if #player.shopSkill ~= 0 then
        self:updateSkill(player)
        return
    end

    table.sort(SkillConfig.Skills, function(a, b)
        return a.Id < b.Id
    end)
    for _, Value in pairs(SkillConfig.Skills) do
        table.insert(player.shopSkill, {
            id = Value.Id,
            status = Define.ItemBuyStatus.Lock
        })
    end

    for j = 1, 3 do
        player.equipmentSkill[tostring(j)] = {
            id = 0,
            position = j
        }
    end
   -- print(json.encode(player.equipmentSkill))
end

function GameSkill:updateSkill(player)

    if not player then
        return
    end

    for _, setting in pairs(SkillConfig.Skills) do

        local find = false
        for _, Value in pairs(player.shopSkill) do
            if  Value.id == setting.Id then
                find = true
                break
            end
        end

        if find == false then
            if player.property.advancedLevel >= setting.advancedId then
                if setting.isHave == Define.DefaultHave.Have then
                    table.insert(player.shopSkill, {
                        id = setting.Id,
                        status = Define.ItemBuyStatus.Buy
                    })
                else
                    table.insert(player.shopSkill, {
                        id = setting.Id,
                        status = Define.ItemBuyStatus.Unlock
                    })
                end
            else
                table.insert(player.shopSkill, {
                    id = setting.Id,
                    status = Define.ItemBuyStatus.Lock
                })
            end
        end
    end
end

function GameSkill:initAdvancedSkillItem(player, advanceId)

    local data = {}
    for _, Value in pairs(player.shopSkill) do
        local config = SkillConfig:getSkillById(Value.id)
        --print(json.encode(config))
        --print(json.encode(Value))
        if config and Value.status == Define.ItemBuyStatus.Lock and config.advancedId == advanceId
                and config.isHave == Define.DefaultHave.NotHave then
            Value.status = Define.ItemBuyStatus.Unlock
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end
        if config and Value.status == Define.ItemBuyStatus.Lock and config.advancedId == advanceId
                and config.isHave == Define.DefaultHave.Have then
            Value.status = Define.ItemBuyStatus.Buy
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end

    end
    --print(json.encode(data))
    ShopManager:senderSkillInfo(player, data)
    GameSkill:shareDataToTokenSkill(player, data)
    --


end

function GameSkill:shareDataToTokenSkill(player, data)
    local info = {}

    for _, value in pairs(data) do
        for k, v in pairs(player.tokenShopSkill) do
            if value.Id == v.id then
                v.status = value.Status
                table.insert(info, {
                    Id = value.Id,
                    Status = value.Status
                })
                break
            end
        end
    end
    TokenShopManager:senderTokenSkillInfo(player, data)
end

return GameSkill